parameters.functionCode:
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  const title = d.title || '';
  const link = d.link || d.url || '';
  const content = d.content || d.description || d['content:encoded'] || '';

  // Strip HTML tags for clean text
  const cleanContent = content.replace(/<[^>]*>/g, '').trim();
  // Truncate to ~1500 chars for AI processing
  const truncated = cleanContent.substring(0, 1500);

  results.push({
    json: {
      title,
      link,
      raw_content: truncated,
      pub_date: d.pubDate || d.isoDate || new Date().toISOString(),
      author: d.creator || d.author || 'Unknown'
    }
  });
}

return results;

