parameters.functionCode:
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  let aiResponse;

  try {
    const content = d.message?.content || d.choices?.[0]?.message?.content || d.text || '{}';
    aiResponse = JSON.parse(content);
  } catch (e) {
    aiResponse = {
      tweet: d.title?.substring(0, 240) + '...',
      linkedin_post: d.title || 'Check out this article',
      hashtags: ['tech', 'news']
    };
  }

  const hashtags = (aiResponse.hashtags || []).map(t => t.startsWith('#') ? t : `#${t}`).join(' ');
  const tweetText = `${aiResponse.tweet}\n\n${d.link || ''}\n\n${hashtags}`.trim();
  const linkedinText = `${aiResponse.linkedin_post}\n\n${hashtags}\n\n${d.link || ''}`;

  results.push({
    json: {
      ...d,
      tweet_text: tweetText,
      linkedin_text: linkedinText,
      hashtags: aiResponse.hashtags || [],
      ai_summary: aiResponse
    }
  });
}

return results;

